<?php
namespace App\Modules\Hr\Advance\Models;
use App\Modules\Hr\Advance\Enums\AdvanceStatus; use App\Modules\Hr\Core\Traits\BelongsToLegalEntity; use App\Modules\Hr\Personnel\Models\HrEmployee; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; use Illuminate\Database\Eloquent\Relations\HasMany;
class HrAdvance extends Model { use BelongsToLegalEntity; protected $fillable=['legal_entity_id','employee_id','requested_amount','currency','installment_count','requested_payment_date','reason','status','source_key','payload_hash','requested_by','decided_by','decided_at','decision_note','paid_by','paid_at','payment_reference']; protected function casts():array{return ['requested_amount'=>'decimal:2','installment_count'=>'integer','requested_payment_date'=>'date','status'=>AdvanceStatus::class,'decided_at'=>'datetime','paid_at'=>'datetime'];} public function employee():BelongsTo{return $this->belongsTo(HrEmployee::class);} public function transactions():HasMany{return $this->hasMany(HrAdvanceTransaction::class,'advance_id')->orderBy('transaction_date')->orderBy('id');} public function getRepaidAmountAttribute():string{return number_format((float)$this->transactions()->whereIn('type',['repayment','payroll_deduction'])->sum('amount'),2,'.','');} public function getOutstandingAmountAttribute():string{return number_format(max(0,(float)$this->requested_amount-(float)$this->repaid_amount),2,'.','');} }
